window.MessagePack = (() => {
  function encode(obj) {
    if (obj === null) return new Uint8Array([0xc0]);
    if (obj === false) return new Uint8Array([0xc2]);
    if (obj === true) return new Uint8Array([0xc3]);
    if (typeof obj === 'number') {
      if (Number.isInteger(obj)) {
        if (obj >= 0 && obj <= 0x7f) return new Uint8Array([obj]);
        if (obj >= -32 && obj < 0) return new Uint8Array([0xe0 | (obj + 32)]);
        if (obj >= 0 && obj <= 0xff) return new Uint8Array([0xcc, obj]);
        if (obj >= 0 && obj <= 0xffff) return new Uint8Array([0xcd, obj >> 8, obj & 0xff]);
      }
      const buf = new ArrayBuffer(9);
      const view = new DataView(buf);
      view.setUint8(0, 0xcb);
      view.setFloat64(1, obj);
      return new Uint8Array(buf);
    }
    if (typeof obj === 'string') {
      const bytes = new TextEncoder().encode(obj);
      const len = bytes.length;
      let header;
      if (len < 32) header = new Uint8Array([0xa0 | len]);
      else if (len < 256) header = new Uint8Array([0xd9, len]);
      else if (len < 65536) header = new Uint8Array([0xda, len >> 8, len & 0xff]);
      const res = new Uint8Array(header.length + len);
      res.set(header); res.set(bytes, header.length);
      return res;
    }
    if (Array.isArray(obj)) {
      const len = obj.length;
      let header;
      if (len < 16) header = new Uint8Array([0x90 | len]);
      else header = new Uint8Array([0xdc, len >> 8, len & 0xff]);
      const encoded = obj.map(encode);
      const totalLen = header.length + encoded.reduce((s, b) => s + b.length, 0);
      const res = new Uint8Array(totalLen);
      res.set(header);
      let off = header.length;
      for (const b of encoded) { res.set(b, off); off += b.length; }
      return res;
    }
    if (typeof obj === 'object') {
      const keys = Object.keys(obj);
      const len = keys.length;
      let header;
      if (len < 16) header = new Uint8Array([0x80 | len]);
      else header = new Uint8Array([0xde, len >> 8, len & 0xff]);
      const resParts = [header];
      for (const k of keys) { resParts.push(encode(k)); resParts.push(encode(obj[k])); }
      const totalLen = resParts.reduce((s, b) => s + b.length, 0);
      const res = new Uint8Array(totalLen);
      let off = 0;
      for (const b of resParts) { res.set(b, off); off += b.length; }
      return res;
    }
    return new Uint8Array(0);
  }

  function decode(uint8) {
    let offset = 0;
    function read() {
      const b = uint8[offset++];
      if (b <= 0x7f) return b;
      if (b >= 0x80 && b <= 0x8f) return readMap(b & 0xf);
      if (b >= 0x90 && b <= 0x9f) return readArray(b & 0xf);
      if (b >= 0xa0 && b <= 0xbf) return readStr(b & 0x1f);
      if (b >= 0xe0) return b - 256;
      if (b === 0xc0) return null;
      if (b === 0xc2) return false;
      if (b === 0xc3) return true;
      if (b === 0xcc) return uint8[offset++];
      if (b === 0xcd) return (uint8[offset++] << 8) | uint8[offset++];
      if (b === 0xce) return ((uint8[offset++] << 24) | (uint8[offset++] << 16) | (uint8[offset++] << 8) | uint8[offset++]) >>> 0;
      if (b === 0xcb) {
        const v = new DataView(uint8.buffer, uint8.byteOffset + offset, 8).getFloat64(0);
        offset += 8; return v;
      }
      if (b === 0xd9) return readStr(uint8[offset++]);
      if (b === 0xda) return readStr((uint8[offset++] << 8) | uint8[offset++]);
      if (b === 0xdc) return readArray((uint8[offset++] << 8) | uint8[offset++]);
      if (b === 0xde) return readMap((uint8[offset++] << 8) | uint8[offset++]);
      return undefined;
    }
    function readStr(len) {
      const s = new TextDecoder().decode(uint8.subarray(offset, offset + len));
      offset += len; return s;
    }
    function readArray(len) {
      const a = []; for (let i = 0; i < len; i++) a.push(read());
      return a;
    }
    function readMap(len) {
      const m = {}; for (let i = 0; i < len; i++) m[read()] = read();
      return m;
    }
    return read();
  }

  return { encode, decode };
})();
